{"file_path": "/project/ktlint-ruleset-standard/src/test/kotlin/com/pinterest/ktlint/ruleset/standard/rules/FunctionBodyWhitespaceConflictTest.kt", "content": "package com.pinterest.ktlint.ruleset.standard.rules

import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRuleSet
import org.junit.jupiter.api.Test

/**
 * Integration test to verify that the conflict between multiple rules inserting 
 * whitespace before function body blocks has been resolved.
 * 
 * This was reported as an issue where FunctionStartOfBodySpacingRule, SpacingAroundCurlyRule,
 * and FunctionSignatureRule were all trying to insert whitespace at the same location,
 * causing format to not converge in 3 consecutive runs.
 */
class FunctionBodyWhitespaceConflictTest {

    private val ruleSetAssertThat = assertThatRuleSet { 
        setOf(
            FunctionStartOfBodySpacingRule(),
            SpacingAroundCurlyRule(), 
            FunctionSignatureRule()
        )
    }

    @Test
    fun `Function with missing whitespace before body block should format correctly in one pass`() {
        val code = """
            class UampNotificationManager(
                private val context: Context,
                sessionToken: MediaSessionCompat.Token,
                notificationListener: PlayerNotificationManager.NotificationListener,
            ) {
                fun showNotificationForPlayer(player: Player){
                    notificationManager.setPlayer(player)
                }
            }
        """.trimIndent()

        val formattedCode = """
            class UampNotificationManager(
                private val context: Context,
                sessionToken: MediaSessionCompat.Token,
                notificationListener: PlayerNotificationManager.NotificationListener,
            ) {
                fun showNotificationForPlayer(player: Player) {
                    notificationManager.setPlayer(player)
                }
            }
        """.trimIndent()

        // This should format correctly without requiring multiple passes
        // Previously this would fail with "Format was not able to resolve all violations 
        // which (theoretically) can be autocorrected in 3 consecutive runs of format"
        ruleSetAssertThat(code).isFormattedAs(formattedCode)
